import{_ as t,o,c as d,a2 as c}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"VitePress 이관 — Contracts (Phase 1)","description":"","frontmatter":{"title":"VitePress 이관 — Contracts (Phase 1)","feature_id":"007","created":"2026-06-01 22:16 (KST)"},"headers":[],"relativePath":"specs/007-vitepress-docs-migration/contracts/site-and-pipeline.md","filePath":"specs/007-vitepress-docs-migration/contracts/site-and-pipeline.md","lastUpdated":null}'),s={name:"specs/007-vitepress-docs-migration/contracts/site-and-pipeline.md"};function r(a,e,l,i,n,p){return o(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="contracts-사이트-구조-·-빌드-파이프라인" tabindex="-1">Contracts: 사이트 구조 · 빌드 파이프라인 <a class="header-anchor" href="#contracts-사이트-구조-·-빌드-파이프라인" aria-label="Permalink to &quot;Contracts: 사이트 구조 · 빌드 파이프라인&quot;">​</a></h1><p>REST API 는 없다. 이 기능이 노출하는 &quot;계약&quot;은 (1) 사이트 URL/네비 구조, (2) 동기화 스크립트 CLI, (3) 빌드 산출물·CI 입출력이다.</p><h2 id="c-1-url-네비게이션-계약-참조-프로젝트-형태" tabindex="-1">C-1. URL / 네비게이션 계약 (참조 프로젝트 형태) <a class="header-anchor" href="#c-1-url-네비게이션-계약-참조-프로젝트-형태" aria-label="Permalink to &quot;C-1. URL / 네비게이션 계약 (참조 프로젝트 형태)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>경로</th><th>내용</th><th>비고</th></tr></thead><tbody><tr><td><code>/blog/</code></td><td>홈(hero + features)</td><td><code>index.md</code>, <code>layout: home</code></td></tr><tr><td><code>/blog/overview/</code></td><td>개요</td><td>현 <code>docs/intro.md</code> 대체</td></tr><tr><td><code>/blog/journal/</code></td><td>저널 목록(자동, 최근 먼저)</td><td>data loader 렌더</td></tr><tr><td><code>/blog/journal/&lt;slug&gt;</code></td><td>저널 글</td><td>12편</td></tr><tr><td><code>/blog/specs/</code></td><td>명세 인덱스</td><td>자동 사이드바</td></tr><tr><td><code>/blog/specs/&lt;NNN-feature&gt;/&lt;doc&gt;</code></td><td>개별 spec 문서</td><td>sync 산출물</td></tr></tbody></table><ul><li><strong>상단 nav</strong>: 홈 · 개요 · 저널 · 명세 (참조의 홈/개요/전문/주제별/작업로그 패턴을 이 저장소 콘텐츠에 매핑).</li><li><strong>사이드바</strong>: 개요/저널은 정적, <code>/specs/</code> 는 자동 생성(번호 내림차순).</li><li><strong>검색</strong>: 로컬, 한국어 UI 문자열.</li><li><strong>이전/다음·최종수정일·푸터·outline</strong>: 활성.</li></ul><h2 id="c-2-동기화-스크립트-cli-계약" tabindex="-1">C-2. 동기화 스크립트 CLI 계약 <a class="header-anchor" href="#c-2-동기화-스크립트-cli-계약" aria-label="Permalink to &quot;C-2. 동기화 스크립트 CLI 계약&quot;">​</a></h2><ul><li><strong>스크립트</strong>: <code>scripts/sync-specs-to-vitepress.sh</code> (+ <code>.ps1</code> 동등본)</li><li><strong>입력</strong>: <code>specs/**/*.md</code> (<code>*/checklists/*</code> 제외)</li><li><strong>출력</strong>: <ol><li><code>blog/specs/&lt;rel&gt;</code> — 원본 디렉터리 구조 보존 복사.</li><li><code>blog/sidebar.specs.json</code> — VitePress <code>SidebarItem[]</code>, <strong>feature 번호 내림차순</strong>.</li></ol></li><li><strong>부작용</strong>: <code>blog/specs/</code> 의 기존 동기화본 디렉터리 정리 후 재생성(현 sh 의 <code>find -maxdepth 1 -type d -exec rm -rf</code> 정책 유지).</li><li><strong>종료코드</strong>: 성공 0, 실패 비0(파이프라인이 빌드 전 중단).</li><li><strong>로그</strong>: <code>synced N spec file(s)</code> + <code>generated sidebar with M feature(s)</code>.</li><li><strong>불변(보존)</strong>: 리포에 specs 영구 중복 사본을 만들지 않는다(빌드타임 산출).</li></ul><h2 id="c-3-저널-data-loader-계약" tabindex="-1">C-3. 저널 data loader 계약 <a class="header-anchor" href="#c-3-저널-data-loader-계약" aria-label="Permalink to &quot;C-3. 저널 data loader 계약&quot;">​</a></h2><ul><li><strong>모듈</strong>: <code>.vitepress/data/journal.data.mts</code></li><li><strong>export</strong>: <code>export const data: JournalListItem[]</code> (data-model §4)</li><li><strong>정렬 보장</strong>: <code>created</code>(없으면 <code>date</code>) 내림차순. 동률이면 <code>slug</code>/파일명.</li><li><strong>누락 허용</strong>: <code>tags</code>/<code>excerpt</code> 없으면 빈 값. <code>title</code>/<code>created|date</code> 없으면 빌드 경고(가능하면 실패)로 노출 — 모든 저널은 CLAUDE.md 규칙상 둘 다 보유.</li></ul><h2 id="c-4-빌드-ci-계약" tabindex="-1">C-4. 빌드 / CI 계약 <a class="header-anchor" href="#c-4-빌드-ci-계약" aria-label="Permalink to &quot;C-4. 빌드 / CI 계약&quot;">​</a></h2><ul><li><strong>로컬</strong>: <ul><li><code>cd blog &amp;&amp; npm run dev</code> → 개발 서버.</li><li><code>cd blog &amp;&amp; npm run build</code> → <code>blog/.vitepress/dist</code>. <strong>죽은 내부 링크 시 실패</strong>(strict).</li></ul></li><li><strong>CI(<code>publish-blog.yml</code>)</strong>:<table tabindex="0"><thead><tr><th>단계</th><th>계약</th></tr></thead><tbody><tr><td>sync</td><td><code>bash scripts/sync-specs-to-vitepress.sh</code> 성공</td></tr><tr><td>setup-node</td><td>node 24, <code>cache: npm</code>, <code>blog/package-lock.json</code></td></tr><tr><td>build</td><td><code>npm ci &amp;&amp; npm run build</code> (실패 시 배포 중단)</td></tr><tr><td>upload artifact</td><td><code>path: blog/.vitepress/dist</code></td></tr><tr><td>deploy</td><td>GitHub Pages, base <code>/blog/</code></td></tr></tbody></table><ul><li><strong>트리거 paths</strong>: <code>specs/**</code>, <code>blog/**</code>, <code>scripts/sync-specs-to-vitepress.sh</code>, <code>.github/workflows/publish-blog.yml</code>.</li></ul></li></ul><h2 id="c-5-의존성-계약-정리-후" tabindex="-1">C-5. 의존성 계약 (정리 후) <a class="header-anchor" href="#c-5-의존성-계약-정리-후" aria-label="Permalink to &quot;C-5. 의존성 계약 (정리 후)&quot;">​</a></h2><ul><li><code>blog/package.json</code> 의 dependencies 에 <code>@docusaurus/*</code>·<code>react</code>·<code>react-dom</code>· <code>prism-react-renderer</code>·<code>@mdx-js/*</code>·<code>clsx</code> <strong>없음</strong>.</li><li>포함: <code>vitepress</code>, <code>vitepress-plugin-mermaid</code>, <code>mermaid</code>, (<code>vue</code>).</li><li>산출물 번들에 React 런타임 부재 → SC-7.</li></ul>',13)])])}const h=t(s,[["render",r]]);export{u as __pageData,h as default};
